import React, { useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import './outflowFunc.css';
import AddOutflow from './AddOutflow.js'
import EditOutflow from './EditOutflow.js'


const OutflowFunc = ([materials, locations, outflows, setOutflows, projects, employees]) => {
  
  const [editingOutflow, setEditingOutflow] = useState(null);

  const handleAdd = useCallback((newOutflow) => {
    
    // Make a POST request to add the new outflow
    fetch('/outflowAPI', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newOutflow),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding outflow');
        }
      }) 
      .catch((error) => {
        console.log('Error adding outflow:', error);
      });
  }, []);

  const handleDelete = useCallback((deletedoutflow) => {
    const isConfirmed = window.confirm('Are you sure you want to delete this outflow?');
  
    if (isConfirmed) {
      fetch(`/outflowAPI/${deletedoutflow.id}`, {
        method: 'DELETE',
      })
        .then(() => {
          const updatedOutflowList = outflows.filter((p) => p.id !== deletedoutflow.id);
          setOutflows(updatedOutflowList);
        })
        .catch((error) => {
          console.log('Error deleting outflow:', error);
        });
    }
  }, [outflows]);

  const handleEdit = useCallback((outflow) => {
    if (editingOutflow && editingOutflow.id === outflow.id) {
      alert('Outflow is already being edited.');
      return;
    }

    setEditingOutflow(outflow);
  }, [editingOutflow]);


    

  const columns = React.useMemo(
    () => [
      { Header: 'ID', accessor: 'outflowid' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'matid' },
      { Header: 'Material Name', accessor: 'name' },
      { Header: 'Width', accessor: 'width' },
      { Header: 'Lot No', accessor: 'lotnumber' },
      { Header: 'Quantity', accessor: 'quantity' },
      { Header: 'Project', accessor: 'project' },
      { Header: 'Employee', accessor: 'employee' },     
      { Header: 'Date', accessor: 'date' },
      { Header: 'Actions', accessor: 'actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: outflows,
      locations,
      materials,
      initialState: {
        pageIndex: 0,
        pageSize: 10,
        sortBy: [
          {
            id: 'id', // ID column accessor
            desc: true, // Sorting in descending order
          },
        ],
      },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );


return (
    <div>
      <AddOutflow handleAdd={handleAdd} locations={locations} />

      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="outflow-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingOutflow && editingOutflow.id === row.original.id && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditOutflow outflow={editingOutflow} handleUpdate={handleUpdate} vendors={vendors} locations={locations} materials={materials} outflows={outflows} setOutflows={setOutflows}/>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(outflows.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

export default OutflowFunc;
